<div class="page-head"><h1>Ca học</h1><a class="btn" href="/time-slots/create">Thêm ca học</a></div>
<table><tr><th>Tên ca</th><th>Bắt đầu</th><th>Kết thúc</th><th></th></tr><?php foreach ($timeSlots as $slot): ?><tr><td><?= e($slot['slot_name']) ?></td><td><?= e($slot['start_time']) ?></td><td><?= e($slot['end_time']) ?></td><td class="actions"><a class="btn secondary" href="/time-slots/<?= e($slot['time_slot_id']) ?>/edit">Sửa</a><form class="inline" method="post" action="/time-slots/<?= e($slot['time_slot_id']) ?>"><?= csrf_field() ?><?= method_field('DELETE') ?><button class="danger" data-confirm="Xóa ca học?">Xóa</button></form></td></tr><?php endforeach; ?></table>
